sinks.expression:
array_map(
			static function( $recipient ) {
				$recipient = preg_replace( '/[\r\n]+/', ' ', (string) $recipient );
				$recipient = trim( preg_replace( '/\s+/', ' ', $recipient ) );

				return $recipient;
			},
			$parts
		)

array_filter(
				array_map(
					static function( $tag ) {
						$tag = sanitize_text_field( (string) $tag );

						return preg_match( '/^%%[a-z0-9_]+%%$/i', $tag ) ? $tag : '';
					},
					$tags
				)
			)

array_map(
					static function( $tag ) {
						$tag = sanitize_text_field( (string) $tag );

						return preg_match( '/^%%[a-z0-9_]+%%$/i', $tag ) ? $tag : '';
					},
					$tags
				)

array_filter(
				is_array( $requested_tags ) ? $requested_tags : [],
				static function( $tag ) use ( $available_lookup ) {
					return is_string( $tag ) && in_array( strtolower( $tag ), $available_lookup, true );
				}
			)

array_filter(
				array_map(
					static function( $type ) {
						return sanitize_key( (string) $type );
					},
					$supported
				)
			)

array_map(
			static function( $tag ) {
				return '<code>' . esc_html( sanitize_text_field( $tag ) ) . '</code>';
			},
			$tags
		)

